716:  * This is the RPC `scheduler' (or rather, the finite state machine).
717:  */
718: static void __rpc_execute(struct rpc_task *task)
719: {
720: 	struct rpc_wait_queue *queue;
721: 	int task_is_async = RPC_IS_ASYNC(task);
722: 	int status = 0;
723: 
